package pe.edu.utp.tmo.controller; import java.security.Principal; import java.time.LocalDateTime; import org.springframework.format.annotation.DateTimeFormat; import org.springframework.http.*; import org.springframework.web.bind.annotation.*; import pe.edu.utp.tmo.service.ReportService; import pe.edu.utp.tmo.util.FileNameSanitizer; @RestController @RequestMapping("/api/reports") public class ReportController{ private final ReportService s; public ReportController(ReportService s){this.s=s;} @GetMapping(value="/tmo/excel",produces="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet") ResponseEntity<byte[]> excel(@RequestParam @DateTimeFormat(iso=DateTimeFormat.ISO.DATE_TIME) LocalDateTime inicio,@RequestParam @DateTimeFormat(iso=DateTimeFormat.ISO.DATE_TIME) LocalDateTime fin,Principal p){return ResponseEntity.ok().contentType(MediaType.parseMediaType("application/vnd.openxmlformats-officedocument.spreadsheetml.sheet")).header(HttpHeaders.CONTENT_DISPOSITION,ContentDisposition.attachment().filename(FileNameSanitizer.safeXlsx("reporte_tmo")).build().toString()).body(s.excel(p.getName(),inicio,fin));}}